#include <stdio.h>
#include <math.h>
#define MAX_N 51
#define MAX_T 17
#define EPS 1e-6

int T, N;
double x[MAX_N], y[MAX_N];

void solve() {
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        scanf("%lf %lf", &x[i], &y[i]);
    }
    // Try all possible combinations of laying off at most four employees
    double min_radius = 1e9;
    double cx, cy;
    for (int mask = 0; mask < (1 << N); mask++) {
        if (__builtin_popcount(mask) > 4) continue;
        int count = 0;
        double sum_x = 0, sum_y = 0;
        for (int i = 0; i < N; i++) {
            if (!(mask & (1 << i))) {
                sum_x += x[i];
                sum_y += y[i];
                count++;
            }
        }
        if (count == 0) continue;
        cx = sum_x / count;
        cy = sum_y / count;
        double radius = 0;
        for (int i = 0; i < N; i++) {
            if (!(mask & (1 << i))) {
                double dist = sqrt((x[i] - cx) * (x[i] - cx) + (y[i] - cy) * (y[i] - cy));
                radius = fmax(radius, dist);
            }
        }
        min_radius = fmin(min_radius, radius);
    }
    printf("%.4f %.4f %.4f\n", cx, cy, min_radius);
}

int main() {
    scanf("%d", &T);
    while (T--) {
        solve();
    }
    return 0;
}

