const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const x = new Array(N);
    const y = new Array(N);
    for (let j = 0; j < N; j++) {
        const [xi, yi] = readline().split(' ').map(Number);
        x[j] = xi;
        y[j] = yi;
    }
    // Try all possible combinations of laying off at most four employees
    let min_radius = 1e9;
    let cx, cy;
    for (let mask = 0; mask < (1 << N); mask++) {
        if (countBits(mask) > 4) continue;
        let count = 0;
        let sum_x = 0, sum_y = 0;
        for (let j = 0; j < N; j++) {
            if (!(mask & (1 << j))) {
                sum_x += x[j];
                sum_y += y[j];
                count++;
            }
        }
        if (count === 0) continue;
        cx = sum_x / count;
        cy = sum_y / count;
        let radius = 0;
        for (let j = 0; j < N; j++) {
            if (!(mask & (1 << j))) {
                const dist = Math.sqrt((x[j] - cx) ** 2 + (y[j] - cy) ** 2);
                radius = Math.max(radius, dist);
            }
        }
        min_radius = Math.min(min_radius, radius);
    }
    console.log(`${cx.toFixed(4)} ${cy.toFixed(4)} ${min_radius.toFixed(4)}`);
}
function countBits(n) {
    let count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}
